effect.shader:
#define PI 3.1415926536

vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

float rays(vec2 st, float pixelSize, float feather, float width, float count, float innerRadius, float outerRadius, float radialFeather, float bendStrength, float bendFrequency, float bendPhase, float angle) {
    float r = length(st);
    float theta = (atan(st.x,st.y)+angle)/(2.0*PI);
    theta += sin(r*bendFrequency+bendPhase)*bendStrength;
    float sweep = 1./count;
    float t = mod(theta,sweep)/sweep;
    float h = feather/2. * pixelSize/r;
    float halfWidth = width/2.;
    float low = smoothstep(0.5-halfWidth-h,0.5-halfWidth+h,t);
    float high = smoothstep(0.5+halfWidth+h,0.5+halfWidth-h,t);
    float rf = radialFeather/2. * pixelSize;
    //float rt0 = abs(t-0.5)/halfWidth;
    //float rt1 = 1.-clamp((outerRadius-r)/halfWidth,0.,1.);
    //float rt = rt0*rt1;
    float orad = outerRadius; //-((cos(rt))*rounding);
    float ir = innerRadius;
    float inside = smoothstep(ir-rf, ir+rf, r);
    float outside = smoothstep(orad+rf, orad-rf, r);

    //float insideRound = smoothstep(ir-rounding, ir+rounding, r);
    //float outsideRound = smoothstep(or+rounding, or-rounding, r);
    //float lowRound = smoothstep(0.5-halfWidth-rounding,0.5-halfWidth+rounding,t);
    //float highRound = smoothstep(0.5+halfWidth+rounding,0.5+halfWidth-rounding,t);
    //
    //float roundLimit = smoothstep(0.5,0.501,insideRound * outsideRound * lowRound * highRound);

    return low*high*inside*outside;
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = acLayerNorm;
    st.y = 1. - st.y;
    st -= 0.5;
    st.x *= acLayerSize.x/acLayerSize.y;
    float pixelSize = 1./length(getTexSize(inputImg.size));

    float p = rays(st-position/1000.0, pixelSize, feather, rayWidth, pointCount, innerRadius, outerRadius, radialFeather, bendStrength/10., bendFrequency, bendPhase, angle/57.2958);

    vec4 adjColor = color * p;

    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*adjColor.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-adjColor.rgb)),1.0) * texColor.a;
    } else {
        result = adjColor*texColor.a;
        result = texColor*(1.-result.a) + result;
    }
    gl_FragColor = mix(texColor,result,alpha);
}
